import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

class CalculatorTest {

    private Calculator calc = new Calculator();

    @Test  // This annotation marks it as a test method
    void testAddition() {
        // Arrange: set up the inputs
        int result = calc.add(3, 5);
        // Act & Assert: check the output equals expected
        assertEquals(8, result, "3 + 5 should equal 8");
    }

    @Test
    void testDivisionByZero() {
        // Test that an exception is thrown
        assertThrows(ArithmeticException.class, () -> {
            calc.divide(10, 0);
        });
    }

    @Test
    void testAdditionWithNegatives() {
        assertEquals(-2, calc.add(-5, 3));
    }
}
// Expected: all three tests pass (green bar in IDE)
